function validate(args, output) {
    const str1 = args[0], str2 = args[1];
    if (typeof output !== 'string') return false;
    function isSubseq(a, b) {
        let i = 0;
        for (let j = 0; j < b.length && i < a.length; j++) {
            if (b[j] === a[i]) i++;
        }
        return i === a.length;
    }
    if (!isSubseq(str1, output)) return false;
    if (!isSubseq(str2, output)) return false;
    const m = str1.length, n = str2.length;
    const dp = Array.from({ length: m + 1 }, () => new Array(n + 1).fill(0));
    for (let i = 1; i <= m; i++) {
        for (let j = 1; j <= n; j++) {
            if (str1[i - 1] === str2[j - 1]) dp[i][j] = dp[i - 1][j - 1] + 1;
            else dp[i][j] = Math.max(dp[i - 1][j], dp[i][j - 1]);
        }
    }
    const lcs = dp[m][n];
    return output.length === m + n - lcs;
}

